html:
{% set settings = frappe.db.get_singles_dict('School Settings') %}
<!DOCTYPE html>
<html lang="pt">
<head>
<meta charset="UTF-8">
<style>
  body { font-family: Arial, Helvetica, sans-serif; font-size: 12px; color: #1e293b; margin: 0; padding: 24px; }
  .pf-header { text-align: center; margin-bottom: 24px; border-bottom: 2px solid #024ba5; padding-bottom: 16px; }
  .pf-logo { height: 64px; margin-bottom: 8px; }
  .pf-school { font-size: 18px; font-weight: 700; color: #024ba5; }
  .pf-title { font-size: 15px; font-weight: 700; color: #374151; margin-top: 4px; letter-spacing: 0.04em; text-transform: uppercase; }
  .pf-ref { font-size: 11px; color: #64748b; margin-top: 2px; }
  .pf-info { display: flex; gap: 16px; margin-bottom: 20px; }
  .pf-info-block { flex: 1; border: 1px solid #e2e8f0; border-radius: 6px; padding: 10px 14px; }
  .pf-label { font-size: 9px; font-weight: 700; text-transform: uppercase; letter-spacing: 0.07em; color: #64748b; margin-bottom: 3px; }
  .pf-value { font-size: 13px; font-weight: 600; color: #1e293b; }
  table { width: 100%; border-collapse: collapse; margin-bottom: 16px; }
  thead th { background: #024ba5; color: #fff; padding: 8px 12px; text-align: left; font-size: 11px; font-weight: 600; }
  thead th.num { text-align: right; }
  tbody td { padding: 7px 12px; border-bottom: 1px solid #f1f5f9; font-size: 12px; }
  tbody td.num { text-align: right; }
  tbody tr:hover td { background: #f8fafc; }
  tfoot td { padding: 8px 12px; font-weight: 700; }
  .tfoot-sub { color: #374151; border-top: 1px solid #e2e8f0; }
  .tfoot-discount { color: #059669; }
  .tfoot-total { background: #eff6ff; color: #024ba5; font-size: 14px; border-top: 2px solid #024ba5; }
  .tfoot-total td.num { font-size: 15px; }
  .pf-payments { margin-bottom: 20px; }
  .pf-payments-title { font-size: 11px; font-weight: 700; text-transform: uppercase; letter-spacing: 0.06em; color: #64748b; margin-bottom: 8px; }
  .pf-notes { background: #f8fafc; border: 1px solid #e2e8f0; border-radius: 6px; padding: 10px 14px; margin-bottom: 20px; font-size: 12px; }
  .pf-notes-title { font-size: 10px; font-weight: 700; color: #64748b; text-transform: uppercase; margin-bottom: 4px; }
  .pf-signatures { display: flex; justify-content: space-between; margin-top: 48px; }
  .pf-sig-line { text-align: center; width: 45%; }
  .pf-sig-line .line { border-top: 1px solid #374151; padding-top: 6px; font-size: 11px; color: #64748b; }
  .pf-footer { margin-top: 24px; text-align: center; font-size: 10px; color: #94a3b8; border-top: 1px solid #f1f5f9; padding-top: 8px; }
  .badge-discount { display: inline-block; background: #d1fae5; color: #065f46; padding: 2px 10px; border-radius: 12px; font-size: 11px; font-weight: 700; }
</style>
</head>
<body>

<div class="pf-header">
  {% if settings.school_logo %}
  <img src="{{ settings.school_logo }}" class="pf-logo">
  {% endif %}
  <div class="pf-school">{{ settings.school_name or 'Escola' }}</div>
  <div class="pf-title">Adiantamento de Pagamento</div>
  <div class="pf-ref">{{ doc.name }} &nbsp;·&nbsp; {{ frappe.utils.formatdate(doc.payment_date) }}</div>
</div>

<div class="pf-info">
  <div class="pf-info-block">
    <div class="pf-label">Aluno</div>
    <div class="pf-value">{{ doc.student_full_name }}</div>
    {% if doc.school_class %}
    <div style="font-size:11px;color:#64748b;margin-top:4px;">{{ doc.school_class }}</div>
    {% endif %}
  </div>
  <div class="pf-info-block">
    <div class="pf-label">Ano Lectivo</div>
    <div class="pf-value">{{ doc.academic_year }}</div>
    <div style="font-size:11px;color:#64748b;margin-top:4px;">{{ doc.total_periods }} período(s) coberto(s)</div>
  </div>
  <div class="pf-info-block">
    <div class="pf-label">Documento</div>
    <div class="pf-value">{{ doc.name }}</div>
    {% if doc.sales_invoice %}
    <div style="font-size:11px;color:#64748b;margin-top:4px;">Factura: {{ doc.sales_invoice }}</div>
    {% endif %}
  </div>
</div>

<table>
  <thead>
    <tr>
      <th>Período</th>
      <th>Data Prevista de Emissão</th>
      <th>Modo</th>
      <th class="num">Valor Base (MZN)</th>
    </tr>
  </thead>
  <tbody>
    {% for p in doc.periods %}
    <tr>
      <td><strong>{{ p.period_label }}</strong></td>
      <td>{{ frappe.utils.formatdate(p.posting_date) }}</td>
      <td style="color:#64748b;">{{ p.billing_mode }}</td>
      <td class="num">{{ frappe.utils.fmt_money(p.gross_amount, currency='MZN') }}</td>
    </tr>
    {% endfor %}
  </tbody>
  <tfoot>
    <tr class="tfoot-sub">
      <td colspan="3">Subtotal &nbsp;({{ doc.total_periods }} períodos)</td>
      <td class="num">{{ frappe.utils.fmt_money(doc.gross_total, currency='MZN') }}</td>
    </tr>
    {% if doc.discount_percent > 0 %}
    <tr class="tfoot-discount">
      <td colspan="3">
        Desconto &nbsp;<span class="badge-discount">{{ doc.discount_percent | int }}% — {{ doc.discount_reason }}</span>
      </td>
      <td class="num">− {{ frappe.utils.fmt_money(doc.discount_total, currency='MZN') }}</td>
    </tr>
    {% endif %}
    <tr class="tfoot-total">
      <td colspan="3"><strong>TOTAL A PAGAR</strong></td>
      <td class="num">{{ frappe.utils.fmt_money(doc.net_total, currency='MZN') }}</td>
    </tr>
  </tfoot>
</table>

{% if doc.payments %}
<div class="pf-payments">
  <div class="pf-payments-title">Modos de Pagamento</div>
  <table>
    <thead>
      <tr>
        <th>Modo de Pagamento</th>
        <th class="num">Valor (MZN)</th>
      </tr>
    </thead>
    <tbody>
      {% for p in doc.payments %}
      <tr>
        <td>{{ p.mode_of_payment }}</td>
        <td class="num">{{ frappe.utils.fmt_money(p.amount, currency='MZN') }}</td>
      </tr>
      {% endfor %}
    </tbody>
  </table>
</div>
{% endif %}

{% if doc.notes %}
<div class="pf-notes">
  <div class="pf-notes-title">Observações</div>
  {{ doc.notes }}
</div>
{% endif %}

<div class="pf-signatures">
  <div class="pf-sig-line">
    <div class="line">Responsável pela Escola</div>
  </div>
  <div class="pf-sig-line">
    <div class="line">Encarregado de Educação</div>
  </div>
</div>

<div class="pf-footer">
  Emitido em {{ frappe.utils.formatdate(frappe.utils.today()) }}
  &nbsp;·&nbsp; {{ doc.name }}
  {% if doc.sales_invoice %}&nbsp;·&nbsp; Factura: {{ doc.sales_invoice }}{% endif %}
</div>

</body>
</html>
